  1→import { useInfiniteQuery, useQueryClient } from "@tanstack/react-query";
  2→import { addReplyOpinion, getOpinionReply } from "../../../API/Api";
  3→import { useState, useRef } from "react";
  4→import { useAuth } from "../../Context/useAuth";
  5→import { motion, AnimatePresence } from "framer-motion";
  6→import formatPostDate from "../../../helpers/formatDateString";
  7→import VerifiedBadge from "../Badge/VerifiedBadge";
  8→import MentionText from "../mentions/MentionText";
  9→
 10→const MAX_VISUAL_DEPTH = 4;
 11→
 12→const OpinionsReplyCard = ({ opinionId, depth = 0 }) => {
 13→    const queryClient = useQueryClient();
 14→    const { user, session } = useAuth();
 15→
 16→    const [showReply, setShowReply] = useState(false);
 17→    const [replyOpinion, setReplyOpinion] = useState('');
 18→    const [isTypingId, setIsTypingId] = useState('');
 19→    const [showReplyButtonId, setShowReplyButtonId] = useState('');
 20→
 21→    const textAreaRef = useRef(null);
 22→
 23→    const { data, isLoading, hasNextPage, isFetchingNextPage, fetchNextPage } = useInfiniteQuery({
 24→        queryKey: ['getReplyOpinion', opinionId],
 25→        queryFn: ({ queryKey, pageParam = null }) => getOpinionReply(queryKey[1], 10, pageParam),
 26→        getNextPageParam: (lastPage) => {
 27→            if (lastPage?.hasMore) {
 28→                const lastReply = lastPage?.data[lastPage?.data.length - 1];
 29→                return lastReply.id;
 30→            }
 31→            return undefined;
 32→        },
 33→        enabled: !!opinionId,
 34→        refetchOnWindowFocus: false,
 35→        staleTime: 1000 * 60 * 5
 36→    });
 37→
 38→    const handleSubmitReplyOpinion = async (reply, receiver_id, sender_id, parent_id) => {
 39→        try {
 40→            const formadata = new FormData();
 41→            formadata.append('opinion', reply);
 42→            await addReplyOpinion(formadata, receiver_id, sender_id, parent_id, session?.access_token);
 43→            queryClient.invalidateQueries({ queryKey: ['getReplyOpinion', opinionId] });
 44→            queryClient.invalidateQueries({ queryKey: ['getOpinions'] });
 45→            queryClient.invalidateQueries({ queryKey: ['getViewOpinion'] });
 46→            setReplyOpinion('');
 47→            if (textAreaRef.current) {
 48→                textAreaRef.current.innerText = '';
 49→            }
 50→        } catch (error) {
 51→            console.error(error);
 52→            setReplyOpinion('');
 53→            if (textAreaRef.current) {
 54→                textAreaRef.current.innerText = '';
 55→            }
 56→            queryClient.invalidateQueries({ queryKey: ['getReplyOpinion', opinionId] });
 57→            queryClient.invalidateQueries({ queryKey: ['getOpinions'] });
 58→            queryClient.invalidateQueries({ queryKey: ['getViewOpinion'] });
 59→        }
 60→    };
 61→
 62→    const cancelTyping = () => {
 63→        setIsTypingId('');
 64→        setReplyOpinion('');
 65→        if (textAreaRef.current) {
 66→            textAreaRef.current.innerText = '';
 67→            textAreaRef.current.blur();
 68→        }
 69→        setShowReplyButtonId('');
 70→    };
 71→
 72→    const visualDepth = Math.min(depth, MAX_VISUAL_DEPTH);
 73→    const opinioData = data?.pages.flatMap((page) => page.data) || [];
 74→
 75→    return (
 76→        <div
 77→            className="rc-thread"
 78→            style={{ '--depth': visualDepth }}
 79→        >
 80→            {opinioData?.map((opinion, index) => (
 81→                <motion.div
 82→                    className="so-card-wrapper rc-card"
 83→                    key={opinion.id}
 84→                    initial={{ opacity: 0, y: 6 }}
 85→                    animate={{ opacity: 1, y: 0 }}
 86→                    transition={{ duration: 0.25, delay: index * 0.03, ease: "easeOut" }}
 87→                >
 88→                    {depth > 0 && <div className="rc-thread-line" />}
 89→
 90→                    <div className="so-card so-card--flat">
 91→                        <div className="so-card-content">
 92→                            <div className="so-user-row">
 93→                                <div className="so-user-meta">
 94→                                    <div className={`so-avatar-outer ${opinion.users?.badge === 'legend' ? 'avatar-ring-legend' : opinion.users?.badge === 'og' ? 'avatar-ring-og' : ''}`}>
 95→                                        <img
 96→                                            className="so-avatar"
 97→                                            src={opinion.users?.image_url || '../assets/profile.jpg'}
 98→                                            alt={`${opinion?.users?.name || "User"} profile picture`}
 99→                                        />
100→                                    </div>
101→                                    <div className="so-name-block">
102→                                        <div className="so-name-line">
103→                                            <span className="so-username">{opinion.users?.name}</span>
104→                                            <VerifiedBadge badge={opinion.users?.badge} size={14}/>
105→                                        </div>
106→                                        <span className="so-handle">{formatPostDate(opinion.created_at)}</span>
107→                                    </div>
108→                                </div>
109→                            </div>
110→
111→                            <div className="so-body">
112→                                <MentionText text={opinion.opinion} />
113→                            </div>
114→
115→                            <div className="so-meta-bar">
116→                                {opinion.reply_count > 0 && (
117→                                    <span
118→                                        className="so-reply-pill"
119→                                        onClick={() => setShowReply(prev => !prev)}
120→                                    >
121→                                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
122→                                            <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
123→                                        </svg>
124→                                        {showReply ? 'Hide' : 'Show'} {opinion.reply_count} {opinion.reply_count === 1 ? 'reply' : 'replies'}
