 15→
 16→const incrementReplyCount = (old, parentId) => {
 17→    if (!old || !Array.isArray(old.pages)) return old;
 18→
 19→    return {
 20→        ...old,
 21→        pages: old.pages.map((page) => ({
 22→            ...page,
 23→            comments: Array.isArray(page?.comments)
 24→                ? page.comments.map((comment) => {
 25→                    if (comment?.id !== parentId) return comment;
 26→                    return {
 27→                        ...comment,
 28→                        reply_count: (comment?.reply_count || 0) + 1,
 29→                    };
 30→                })
 31→                : page?.comments,
 32→        })),
 33→    };
 34→};
 35→
 36→
 37→const CommentsCards = ({comments, postId}) =>{
 38→    const {user, session} = useAuth();
 39→    const userId = user?.userData[0].id;
 40→    const queryClient = useQueryClient();
 41→
 42→    const [showReplyInput, setShowReplyInput] = useState(false);
 43→    const [showReplies, setShowReplies] = useState(false);
 44→
 45→    const [reply, setReply] = useState('')
 46→    const [replyLoaderId, setReplyLoaderId] = useState('');
 47→
 48→    const navigate = useNavigate();
 49→    const replyInputRef = useRef(null);
 50→
 51→    const { textareaProps: mentionTextareaProps, dropdownProps: mentionDropdownProps } = useTextareaMention(reply, setReply, replyInputRef, 200, userId);
 52→
 53→    const clickProfile = handleClickProfile(navigate);
 54→
 55→    const {data, isLoading, fetchNextPage, hasNextPage, isFetchinNextPage} = useInfiniteQuery({
 56→        queryKey: ['getPostReplies', comments.id],
 57→        queryFn: ({pageParam = null, queryKey}) => getPostReplies(queryKey[1], 5, pageParam),
 58→        getNextPageParam: (lastPage) => {
 59→            if(lastPage.hasMore){
 60→                const lastReply = lastPage?.data[lastPage?.data.length - 1];
 61→                return lastReply.id;
 62→            } else{
 63→                return undefined
 64→            }
 65→        },
 66→        refetchOnWindowFocus: false,
 67→        enabled: showReplies,
 68→        staleTime: 1000 * 60 * 5
 69→    })
 70→
 71→    const handleClickReplyButton = (e) =>{
 72→        e.stopPropagation();
 73→        setShowReplyInput(!showReplyInput);
 74→    }
 75→
 76→    const handleShowMoreReplies = () => {
 77→        if(!isFetchinNextPage){
 78→            fetchNextPage();
 79→        }
 80→    }
 81→
 82→    const submitReply = async(parent_id, receiver_id) => {
 83→        const trimmedReply = reply.trim();
 84→        if (!trimmedReply) return;
 85→
 86→        setReplyLoaderId(parent_id)
 87→        queryClient.cancelQueries({ queryKey: ['getPostReplies', parent_id] });
 88→        queryClient.cancelQueries({ queryKey: ['postComments', postId] });
 89→
 90→        const previousReplies = queryClient.getQueryData(['getPostReplies', parent_id]);
 91→        const previousComments = queryClient.getQueryData(['postComments', postId]);
 92→
 93→        const optimisticReply = {
 94→            id: `optimistic-reply-${Date.now()}`,
 95→            post_id: postId,
 96→            parent_id: parent_id,
 97→            comment: trimmedReply,
 98→            created_at: new Date().toISOString(),
 99→            user_id: user?.userData?.[0]?.id,
100→            users: {
101→                id: user?.userData?.[0]?.id,
102→                name: user?.userData?.[0]?.name,
103→                image_url: user?.userData?.[0]?.image_url,
104→                badge: user?.userData?.[0]?.badge,
105→            },
106→            reply_count: 0,
107→        };
108→
109→        queryClient.setQueryData(['getPostReplies', parent_id], (old) => {
110→            if (!old || !Array.isArray(old.pages)) {
111→                return {
112→                    pageParams: [null],
113→                    pages: [{ data: [optimisticReply], hasMore: false }],
114→                };
115→            }
116→
117→            return {
118→                ...old,
119→                pages: old.pages.map((page, index) =>
120→                    index === 0
121→                        ? { ...page, data: [optimisticReply, ...(page?.data || [])] }
122→                        : page
123→                ),
124→            };
125→        });
126→        queryClient.setQueryData(['postComments', postId], (old) => incrementReplyCount(old, parent_id));
127→
128→        try {
129→            const formdata = new FormData();
130→            formdata.append('reply', trimmedReply);
131→
132→            const message = await addReply(userId, postId, parent_id, formdata, receiver_id, session?.access_token);
133→            if(message){
134→                // console.log(message);
135→            }
136→            queryClient.invalidateQueries({ queryKey: ['getPostReplies', parent_id] });
137→            queryClient.invalidateQueries({ queryKey: ['postComments', postId] });
138→            setReply('')
139→            setShowReplies(true)
140→        } catch (error) {
141→            queryClient.setQueryData(['getPostReplies', parent_id], previousReplies);
142→            queryClient.setQueryData(['postComments', postId], previousComments);
143→            setReply('')
144→            throw new Error('error adding replies')
145→        } finally {
146→            setReplyLoaderId('')
147→            setShowReplyInput(false);
148→        }
149→    }
150→
151→    useEffect(() =>{
152→        if(showReplyInput && replyInputRef.current){
153→            const timer = setTimeout(() => {
154→                replyInputRef.current.focus();
155→                replyInputRef.current.scrollIntoView({behavior: 'smooth', block: 'center'})
156→            }, 50);
157→
158→            return () => {
159→                clearTimeout(timer)
160→            }
161→        }
162→    }, [showReplyInput])
163→
164→    const replies = data?.pages.flatMap((page) => page.data) || [];
165→
166→    return(
167→        <div className={`cm-card ${comments?.parent_id ? 'cm-card--reply' : ''}`}>
168→            {comments?.parent_id && <div className="cm-thread-line" />}
169→
170→            <div className="cm-card-content">
171→                <div className="cm-user-row">
172→                    <div
173→                        onClick={(e) => clickProfile(e, user?.userData[0].id, comments?.user_id)}
174→                        className={`cm-avatar-container ${comments?.users?.badge === 'legend' ? 'cm-ring-legend' : comments?.users?.badge === 'og' ? 'cm-ring-og' : ''}`}
175→                    >
176→                        <img className="cm-avatar" src={comments?.users?.image_url || '/assets/profile.jpg'} alt={`${comments?.users?.name || "User"} profile picture`} />
177→                    </div>
178→                    <span
179→                        onClick={(e) => clickProfile(e, user?.userData[0].id, comments?.user_id)}
180→                        className="cm-username"
181→                    >
182→                        {comments?.users?.name}
183→                    </span>
184→                    <VerifiedBadge badge={comments?.users?.badge} size={14} />
185→                    <span className="cm-dot">&middot;</span>
186→                    <span className="cm-date">{formatPostDate(comments?.created_at)}</span>
187→                </div>
188→
189→                <p className="cm-body"><MentionText text={comments?.comment} /></p>
190→
191→                <div className="cm-card-actions">
192→                    <button onClick={(e) => handleClickReplyButton(e)} className="cm-reply-btn">
193→                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
194→                            <polyline points="9 17 4 12 9 7" />
195→                            <path d="M20 18v-2a4 4 0 0 0-4-4H4" />
196→                        </svg>
197→                        Reply
198→                    </button>
199→
200→                    {comments?.reply_count > 0 && (
201→                        <button onClick={() => setShowReplies(!showReplies)} className="cm-toggle-replies-btn">
202→                            <motion.svg
203→                                width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"
204→                                animate={{ rotate: showReplies ? 180 : 0 }}
205→                                transition={{ duration: 0.2 }}
206→                            >
207→                                <polyline points="6 9 12 15 18 9" />
208→                            </motion.svg>
209→                            <span className="cm-replies-count-badge">{comments?.reply_count}</span>
210→                            {showReplies ? 'Hide replies' : 'View replies'}
211→                        </button>
212→                    )}
213→                </div>
214→
215→                {replyLoaderId === comments.id && (
216→                    <div className="cm-reply-loading">
217→                        <MoonLoader size={16} color="var(--loader-color)" speedMultiplier={0.8}/>
218→                    </div>
219→                )}
220→
221→                <AnimatePresence>
222→                    {showReplyInput && (
223→                        <motion.div
224→                            initial={{ height: 0, opacity: 0 }}
225→                            animate={{ height: "auto", opacity: 1 }}
226→                            exit={{ height: 0, opacity: 0 }}
227→                            transition={{ duration: 0.2 }}
228→                            className="cm-reply-input-wrapper"
229→                        >
230→                            <ReplyContextChip name={comments?.users?.name} onDismiss={(e) => handleClickReplyButton(e)} />
231→                            <textarea
232→                                ref={replyInputRef}
233→                                maxLength={200}
234→                                value={reply}
235→                                onChange={(e) => { setReply(e.target.value); mentionTextareaProps.onChange(e); }}
236→                                onKeyDown={mentionTextareaProps.onKeyDown}
237→                                onKeyUp={mentionTextareaProps.onKeyUp}
238→                                className="cm-reply-textarea"
239→                                placeholder={`Replying to ${comments?.users?.name}...`}
240→                                rows={1}
241→                            />
242→                            <MentionDropdown {...mentionDropdownProps} />
243→                            <div className="cm-reply-action-row">
244→                                <span className={`cm-reply-char-count ${reply.length > 199 ? 'cm-char-limit' : ''}`}>
245→                                    {reply.length}/200
246→                                </span>
247→                                <button
248→                                    onClick={() => submitReply(comments?.id, comments?.users?.id)}
249→                                    className="cm-reply-submit-btn"
250→                                    disabled={!reply.trim()}
251→                                >
252→                                    Submit
253→                                </button>
254→                            </div>
255→                        </motion.div>
256→                    )}
257→                </AnimatePresence>
258→
259→                <AnimatePresence>
260→                    {showReplies && (
261→                        <motion.div
262→                            initial={{ opacity: 0 }}
263→                            animate={{ opacity: 1 }}
264→                            exit={{ opacity: 0 }}
265→                            transition={{ duration: 0.2 }}
266→                            className="cm-replies-thread"
267→                        >
268→                            {replies?.map((r) => (
269→                                <CommentsCards postId={postId} key={r.id} comments={r}/>
270→                            ))}
271→
272→                            {hasNextPage && (
273→                                <button onClick={handleShowMoreReplies} className="cm-show-more-replies">
274→                                    {isFetchinNextPage ? 'Loading...' : 'Show more replies'}
275→                                </button>
276→                            )}
277→                        </motion.div>
278→                    )}
279→                </AnimatePresence>
280→            </div>
281→        </div>
282→    )
283→}
